    encryption_suite = Fernet(key)

    card_number = 1234567890123456
    encrypted_card_number = encrypt_credit_card(card_number)
    decrypted_card_number = decrypt_credit_card(encrypted_card_number)

    print(f"Encrypted Card Number: {encrypted_card_number}")
    print(f"Decrypted Card Number: {decrypted_card_number}")